/**
 * Data seluruh Kabupaten/Kota di Indonesia (514 wilayah administrasi).
 *
 * Sumber: Badan Pusat Statistik (BPS) — dataset kode wilayah administrasi,
 * dinormalisasi ke format "Kabupaten/Kota <Nama>" dengan title case.
 *
 * File ini murni DATA — jangan taruh logic UI atau state di sini.
 * Reusable untuk: Register, Edit Profile, Dashboard, Ranking Nasional,
 * Ranking Kota, Statistik Pengguna, Filter Leaderboard, Analitik Wilayah.
 */

export type RegionType = "kabupaten" | "kota";

export interface IndonesiaRegion {
  /** Kode wilayah BPS (unik per kabupaten/kota) */
  id: string;
  /** Nilai yang disimpan ke database/form state, mis. "Kota Yogyakarta" */
  value: string;
  /** Teks yang ditampilkan ke pengguna (sama dengan value saat ini) */
  label: string;
  /** "kabupaten" | "kota" — berguna untuk filter/grouping di fitur lain */
  type: RegionType;
  /** Nama provinsi induk — berguna untuk analitik wilayah & grouping */
  province: string;
}

