/** Lookup cepat by value, dipakai saat menampilkan ulang data tersimpan (mis. di Edit Profile). */
export const REGION_BY_VALUE: Record<string, IndonesiaRegion> = Object.fromEntries(
  INDONESIA_REGIONS.map((r) => [r.value, r])
);

/** Daftar nama provinsi unik, terurut alfabet — dipakai untuk filter wilayah di Leaderboard/Analitik. */
export const INDONESIA_PROVINCES: string[] = Array.from(
  new Set(INDONESIA_REGIONS.map((r) => r.province))
).sort((a, b) => a.localeCompare(b));

/**
 * Pencarian sederhana untuk combobox: cocok di awal kata mana pun dalam label
 * (bukan cuma prefix keseluruhan), supaya mengetik "sleman" atau "kab sleman"
 * sama-sama menemukan "Kabupaten Sleman".
 */
export function searchRegions(query: string, limit = 50): IndonesiaRegion[] {
  const q = query.trim().toLowerCase();
  if (!q) return INDONESIA_REGIONS.slice(0, limit);

  const terms = q.split(/\s+/).filter(Boolean);
  return INDONESIA_REGIONS.filter((r) => {
    const haystack = r.label.toLowerCase();
    return terms.every((t) => haystack.includes(t));
  }).slice(0, limit);
}
